// Generate a random integer between 1 and 5 (inclusive)
const randomMinutes = Math.floor(Math.random() * 5) + 1;

// Convert minutes to seconds
const delaySeconds = randomMinutes * 60;

// Return as JSON object (for n8n or similar)
return [{ json: { delaySeconds } }];

// Input 1 = rows from "logs"
// We also need the id & email from Edit Fields1

// Read data from previous nodes
const logs = $input.all();   // all rows returned by logs sheet
const id = $('Extract Tracking Params').item.json.id;
const email = $('Extract Tracking Params').item.json.email;

// Check if matching entry exists
let exists = "no";

for (const item of logs) {
  const row = item.json;

  if (row.id == id && row.email == email) {
    exists = "yes";
    break;
  }
}

// Return single result
return [
  {
    json: {
      exists,
      id,
      email
    }
  }
];
